import React, { useState } from 'react';
import { generateImage } from '../services/openai';

const ImageGenerator = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImages, setGeneratedImages] = useState([]);
  const [selectedStyle, setSelectedStyle] = useState('realistic');
  const [imageSize, setImageSize] = useState('medium');

  const styles = [
    { id: 'realistic', name: 'Realistic', icon: 'ð' },
    { id: 'cartoon', name: 'Cartoon', icon: 'ð' },
    { id: 'abstract', name: 'Abstract', icon: 'ð' },
    { id: 'vintage', name: 'Vintage', icon: 'ð' }
  ];

  const sizes = [
    { id: 'small', name: 'Small (512x512)' },
    { id: 'medium', name: 'Medium (1024x1024)' },
    { id: 'large', name: 'Large (2048x2048)' }
  ];

  const handleGenerate = async () => {
    if (prompt.trim() === '') return;

    setIsGenerating(true);

    try {
      // Generate a single image using the API
      const imageUrl = await generateImage(prompt, selectedStyle, imageSize);

      const newImage = {
        id: Date.now(),
        url: imageUrl,
        prompt: prompt,
        style: selectedStyle,
        size: imageSize
      };

      setGeneratedImages([newImage]);
      setIsGenerating(false);
    } catch (error) {
      console.error('Error generating image:', error);

      // Show error message to user
      setGeneratedImages([]);
      setIsGenerating(false);

      // You could add an error state and show it in the UI
      alert(`Error generating image: ${error.message}`);
    }
  };

  const handleDownload = (image) => {
    // In a real app, this would download the actual generated image
    const link = document.createElement('a');
    link.href = image.url;
    link.download = `generated-image-${image.id}.jpg`;
    link.click();
  };

  const handleClear = () => {
    setPrompt('');
    setGeneratedImages([]);
  };

  return (
    <div className="flex flex-col h-full">
      <div className="bg-white border-b border-gray-200 p-6 flex-shrink-0">
        <h1 className="text-2xl font-bold text-gray-800">AI Image Generator</h1>
        <p className="text-gray-600 mt-1">Create stunning images from text descriptions</p>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-6xl mx-auto space-y-6">
          {/* Input Section */}
          <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Describe the image you want to generate
                </label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="A serene mountain landscape at sunset with a lake in the foreground..."
                  className="w-full h-24 px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent resize-none"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Style
                  </label>
                  <div className="grid grid-cols-2 gap-2">
                    {styles.map((style) => (
                      <button
                        key={style.id}
                        onClick={() => setSelectedStyle(style.id)}
                        className={`flex items-center justify-center space-x-2 px-3 py-2 rounded-lg border transition-colors duration-200 ${
                          selectedStyle === style.id
                            ? 'border-blue-500 bg-blue-50 text-blue-700'
                            : 'border-gray-300 hover:border-gray-400'
                        }`}
                      >
                        <span>{style.icon}</span>
                        <span className="text-sm">{style.name}</span>
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Size
                  </label>
                  <select
                    value={imageSize}
                    onChange={(e) => setImageSize(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    {sizes.map((size) => (
                      <option key={size.id} value={size.id}>
                        {size.name}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="flex space-x-3">
                <button
                  onClick={handleGenerate}
                  disabled={prompt.trim() === '' || isGenerating}
                  className="px-6 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors duration-200"
                >
                  {isGenerating ? 'Generating...' : 'Generate Images'}
                </button>
                <button
                  onClick={handleClear}
                  className="px-6 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors duration-200"
                >
                  Clear
                </button>
              </div>
            </div>
          </div>

          {/* Generated Images */}
          {generatedImages.length > 0 && (
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <h2 className="text-lg font-semibold text-gray-800 mb-4">Generated Images</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                {generatedImages.map((image) => (
                  <div key={image.id} className="relative group">
                    <div className="aspect-square rounded-lg overflow-hidden bg-gray-100">
                      <img src={image.url} alt="Generated" className="w-full h-full object-cover"/>
                    </div>
                    <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-50 transition-opacity duration-200 rounded-lg flex items-center justify-center">
                      <button
                        onClick={() => handleDownload(image)}
                        className="opacity-0 group-hover:opacity-100 bg-white text-gray-800 px-3 py-1 rounded-lg text-sm font-medium transition-opacity duration-200"
                      >
                        Download
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Loading State */}
          {isGenerating && (
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-12">
              <div className="flex flex-col items-center justify-center">
                <div className="flex space-x-2 mb-4">
                  <div className="w-3 h-3 bg-blue-500 rounded-full animate-bounce"></div>
                  <div className="w-3 h-3 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                  <div className="w-3 h-3 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                </div>
                <p className="text-gray-600">Generating your images...</p>
              </div>
            </div>
          )}

          {/* Features */}
